import java.util.Scanner;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine(); // Use nextLine() instead of next() to read the entire line

        // Create a fixed-size buffer
        char[] buffer = new char[10];

        // Copy user input into the buffer with bounds checking
        for (int i = 0; i < Math.min(input.length(), buffer.length); i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Your name is: " + new String(buffer));
    }
}

